"const fs = require('fs');
const readline = require('readline');

async function extractFiles() {
  const fileStream = fs.createReadStream('C:\\Users\\user\\.gemini\\antigravity-ide\\brain\\cb551cbc-739f-4d99-af37-398525cc34ca\\.system_generated\\logs\\transcript.jsonl');

  const rl = readline.createInterface({
    input: fileStream,
    crlfDelay: Infinity
  });

  const filesToExtract = [
    'src/app/globals.css',
    'src/components/layout/Navbar.tsx',
    'src/components/landing/HeroSection.tsx',
    'src/components/landing/TrustSection.tsx',
    'src/components/ui/Button.tsx',
    'src/components/ui/Container.tsx'
  ];

  const extracted = {};

  for await (const line of rl) {
    try {
      const obj = JSON.parse(line);
      if (obj.tool_calls) {
        for (const call of obj.tool_calls) {
          if (call.name === 'write_to_file' || call.name === 'replace_file_content') {
            const target = call.args.TargetFile;
            if (target) {
              const matched = filesToExtract.find(f => target.includes(f));
              if (matched) {
                // Keep overwriting so we get the LAST state before the user asked for "Apple + Linear"
                // The "Apple + Linear" request was at step ~95 or so. We want the V1 state which was around step 70-80.
                if (obj.step_index < 90) { // Limit to before the change
                  extracted[matched] = call.args.CodeContent;
                }
              }
            }
          }
        }
      }
    } catch(e) {}
  }

  for (const [name, content] of Object.entries(extracted)) {
    if (content) {
      console.log(`Writing ${name}...`);
      fs.writeFileSync(`c:\\Projects\\pixelcam\\${name}`, content);
    }
  }
}

extractFiles();"

